class Node:
 def __init__(self, data):
 self.data = data
 self.next = None

class Stack:
 def __init__(self):
 self.head = None

 def push(self, data):
 newNode = Node(data)
 newNode.next = self.head
 self.head = newNode

 def pop(self):
 if self.head == None:
 return None
 poppedData = self.head.data
 self.head = self.head.next
 return poppedData

typedef struct Node {
 int data;
 struct Node* next;
} Node;

typedef struct Queue {
 Node* front;
 Node* rear;
} Queue;

void enqueue(Queue* q, int data) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 newNode->data = data;
 newNode->next = NULL;
 if (q->rear == NULL) {
 q->front = q->rear = newNode;
 } else {
 q->rear->next = newNode;
 q->rear = newNode;
 }
}

int dequeue(Queue* q) {
 if (q->front == NULL) {
 return -1;
 }
 int dequeuedData = q->front->data;
 Node* temp = q->front;
 q->front = q->front->next;
 if (q->front == NULL) {
 q->rear = NULL;
 }
 free(temp);
 return dequeuedData;
}
